async function scanFiles({
  databaseName,
  directory,
  type,
  extension,
  processors,
  postprocess
}) {
  const globString = `${directory}/${type}/**/*.${extension}`;
  console.log(`Glob string: ${globString}`);
  const entries = [];
  const files = await glob(globString);

  for (let i = 0; i < files.length; i++) {
    const filename = files[i];

    const shortpath = _path.default.relative(`${directory}/${type}`, files[i]);

    const pagepath = shortpath.split('/');
    const id = pagepath.pop().replace(/\..+?$/i, '');
    const entry = {
      filename: shortpath,
      extension,
      id,
      path: pagepath
    };

    if (processors) {
      for (let [key, f] of Object.entries(processors)) {
        entry[key] = await f({
          filename
        });
      }
    }

    if (postprocess) {
      await postprocess({
        filename,
        entry
      });
    }

    entries.push(entry);
  }

  console.log(`Scanned files: ${entries.length} *.${extension}`);
  return entries;
}

const fsp = require("fs").promises;

async function postProcessComponent({
  filename,
  entry
}) {
  entry.text = await fsp.readFile(filename, 'utf8');
  entry.parsed = parseES6(entry.text);
}

