async function build(src, dst) {
  const sh = require('shelljs');

  if (!src) {
    throw new Error('Source directory required');
  }

  if (!dst) {
    throw new Error('Destination directory required');
  }

  let srcStat = await _fs.default.promises.stat(src);
  let dstStat = await _fs.default.promises.stat(src);

  if (!srcStat.isDirectory()) {
    throw new Error('Source directory is not a directory');
  }

  console.log(`Working directory: ${process.cwd()}`);
  console.log(`Source: ${src}`);
  console.log(`Destination: ${dst}`);
  const database = await scanDatabase(src, dst);
  console.log('Rebuilt database');
  sh.mkdir('-p', dst);
  sh.cp('-R', `${_path.default.join(__dirname, '../src/template/core')}/*`, `${dst}`);
  sh.cp('-R', `${_path.default.join(__dirname, '../src/template/core')}/.*`, `${dst}`);

  _fs.default.writeFileSync(_path.default.join(dst, "database.json"), JSON.stringify(database, null, 4));
}

async function init(dst) {
  const sh = require('shelljs');

  if (!dst) {
    throw new Error('Destination path not specified!');
  }

  if (sh.test('-e', dst)) {
    throw new Error('Path already exists. Refusing to continue!');
  }

  sh.mkdir(`${dst}`);
  sh.cp('-R', `${_path.default.join(__dirname, '../src/template/sites', 'scratch')}/*`, `${dst}`);
  console.log('OK');
} //
